#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=1e6+5;
int n,x,y,w[MAXN],vis[MAXN],c,b,e,e2,f[MAXN][5];
vector<int> a[MAXN];
int ans;
void fc(int u,int fa)
{
	vis[u]=1;
	FOR(i,0,a[u].size()-1)
	{
		int s=a[u][i];
		if(s==fa)
		{
			continue;
		}
		if(vis[s])
		{
			c=u;
			b=s;
			e=u;
			e2=s;
			continue;
		}
		fc(s,u);
	}
}
void dfs(int u,int fa)
{
	f[u][0]=0;
	f[u][1]=w[u];
	FOR(i,0,a[u].size()-1)
	{
		int s=a[u][i];
		if(s==fa)
		{
			continue;
		}
		dfs(s,u);
		f[u][1]+=f[s][0];
		f[u][0]+=max(f[s][1],f[s][0]);
	}
}
signed main(void)
{
	IOS
	cin>>n;
	FOR(i,1,n)
	{
		int v;
		cin>>w[i]>>v;
		a[i].pb(v);
		a[v].pb(i);
	}
	FOR(i,1,n)
	{
		if(vis[i])
		{
			continue;
		}
		c=-1;
		fc(i,-1);
		if(c==-1)
		{
			dfs(i,-1);
			ans+=max(f[i][0],f[i][1]);
		}
		else
		{
            a[c].erase(find(a[c].begin(),a[c].end(),b));
            a[b].erase(find(a[b].begin(),a[b].end(),c));
			dfs(c,-1);
			int temp_ans=f[c][0];
			dfs(b,-1);
			temp_ans=max(temp_ans,f[b][0]);
			ans+=temp_ans;
		}
	}
	cout<<ans;
	return false;
}
